16	
17	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
18	
19	const mainItemPremium = ({ type }: Item): number => BASE_PREMIUM_BY_TYPE[type];
20	
21	const componentGroupPremium = (count: number): number =>
22	  count === COMPONENT_BLOCK_SIZE
23	    ? COMPONENT_BLOCK_PREMIUM
24	    : count * COMPONENT_BASE_PREMIUM;
25	
26	const countByType = (items: Item[]): Map<string, number> =>
27	  items.reduce(
28	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
29	    new Map<string, number>(),
30	  );
31	
32	const sumComponentPremiums = (components: Item[]): number =>
33	  [...countByType(components).values()]
34	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
35	
36	const sumMainPremiums = (mains: Item[]): number =>
37	  mains.reduce((sum, item) => sum + mainItemPremium(item), 0);
38	
39	const sumBasePremiums = (items: Item[]): number => {
40	  const mains = items.filter(isMainItem);
41	  const components = items.filter((item) => !isMainItem(item));
42	  return sumMainPremiums(mains) + sumComponentPremiums(components);
43	};
44	
45	const quotePremiumFor = (step: Step): { premium: number } => ({
46	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
47	});
48	
49	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
50	  results: scenario.steps.map(quotePremiumFor),
51	});
